runtime.handler:
const stream=await navigator.mediaDevices.getUserMedia({audio:true});
const context=modules['browser.audio'];
if(context.state==='suspended') await context.resume();
const source=context.createMediaStreamSource(stream);
const analyser=context.createAnalyser();
analyser.fftSize=Math.max(32,Math.min(32768,Number(properties.sampleCount||1024)));
source.connect(analyser);
const data=new Float32Array(analyser.fftSize);
await new Promise(r=>setTimeout(r,250));
analyser.getFloatTimeDomainData(data);
stream.getTracks().forEach(t=>t.stop());
source.disconnect();
return {samples:Array.from(data)};

const x=Array.isArray(inputs.samples)?inputs.samples:[];
const bins=Math.max(1,Math.min(Number(properties.bins||64),Math.floor(x.length/2)));
const spectrum=[];
for(let k=0;k<bins;k++){
 let re=0,im=0;
 for(let n=0;n<x.length;n++){
  const a=2*Math.PI*k*n/x.length;
  re+=Number(x[n])*Math.cos(a);
  im-=Number(x[n])*Math.sin(a);
 }
 spectrum.push(Math.sqrt(re*re+im*im)/Math.max(1,x.length));
}
return {spectrum};
